import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useAppContext } from '../context/AppContext';
import { api } from '../services/api';
import Card from '../components/UI/Card';
import RevenueChart from '../components/Dashboard/RevenueChart';
import ExportButton from '../components/Export/ExportButton';

const ProductDetailPage = () => {
  const { sku } = useParams();
  const { period } = useAppContext();
  const [productData, setProductData] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const data = await api.getProductDetail(sku, period);
      setProductData(data);
    } catch (error) {
      console.error("Failed to fetch product ", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, [sku, period]);

  if (loading) return <div className="p-6">Загрузка...</div>;

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Товар: {productData.name}</h1>
        <ExportButton data={productData} scope="product" period={period} logistics="both" sku={sku} />
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <Card>
          <h3 className="text-gray-500 dark:text-gray-400 text-sm">SKU</h3>
          <p className="text-xl font-bold">{productData.sku}</p>
        </Card>
        <Card>
          <h3 className="text-gray-500 dark:text-gray-400 text-sm">Выручка</h3>
          <p className="text-xl font-bold">{productData.revenue.toLocaleString()} ₽</p>
        </Card>
        <Card>
          <h3 className="text-gray-500 dark:text-gray-400 text-sm">Продано</h3>
          <p className="text-xl font-bold">{productData.quantity_sold}</p>
        </Card>
        <Card>
          <h3 className="text-gray-500 dark:text-gray-400 text-sm">Остаток</h3>
          <p className="text-xl font-bold">{productData.stock}</p>
        </Card>
      </div>
      <div className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow mb-6">
        {/* ❌ Было: productData.sales_chart */}
        {/* ✅ Стало: { revenue_chart: productData.sales_chart } */}
        <RevenueChart data={{ revenue_chart: productData.sales_chart }} />
      </div>
    </div>
  );
};

export default ProductDetailPage;
